{
  "treatments": [
    {
      "rank": 1,
      "name": "Surgical Resection (Lobectomy) with Mediastinal Lymph Node Dissection",
      "category": "Standard of Care",
      "intent": null,
      "composite_rating": 9.6,
      "rating_breakdown": {
        "evidence_level": {
          "score": 10,
          "rationale": "Lobectomy is the gold-standard treatment for stage I NSCLC supported by decades of phase 3 RCTs and multiple international guidelines (NCCN, ESMO). JCOG0802 and CALGB 140503 confirmed long-term survival outcomes."
        },
        "survival_benefit": {
          "score": 10,
          "rationale": "5-year overall survival for resected stage IA NSCLC exceeds 90%. JCOG0802 reported 5-year OS of 91.1% with lobectomy and 94.3% with segmentectomy for tumors <=2 cm. Complete surgical resection provides the highest cure rate for stage I disease."
        },
        "accessibility": {
          "score": 10,
          "rationale": "Widely available at all major medical centers worldwide. Standard procedure covered by all insurance plans. Patient is 45 y.o. with ECOG 0 and no comorbidities, making him an ideal surgical candidate."
        },
        "safety_profile": {
          "score": 7,
          "rationale": "Lobectomy carries a 30-day mortality of 1-2% and morbidity of 10-15% including air leak, atrial fibrillation, and pneumonia. VATS/RATS approaches reduce morbidity. Excellent safety in fit patients like this ECOG 0 individual."
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Surgery is universally applicable regardless of biomarker status. Appropriate for all molecular subtypes in stage I disease. Complete resection enables molecular profiling for adjuvant therapy decisions."
        }
      },
      "mechanism_of_action": "Complete surgical excision of the tumor-bearing lobe with systematic mediastinal lymph node dissection. Removes the primary tumor and regional lymph nodes to achieve R0 resection and accurate pathological staging.",
      "key_evidence": {
        "study_name": "JCOG0802/WJOG4607L",
        "journal": "The Lancet",
        "year": 2022,
        "sample_size": 1106,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0.0,
          "p_value": 0.0
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [],
      "ps_requirement": null,
      "notable_side_effects": [
        "Post-operative pain",
        "Air leak",
        "Atrial fibrillation",
        "Pneumonia",
        "Reduced pulmonary function",
        "Venous thromboembolism"
      ],
      "qol_impact": null,
      "availability": "FDA Approved / Standard of Care — universally available",
      "source_urls": [
        "https://www.nccn.org/guidelines/guidelines-detail?category=1&id=1450",
        "https://www.sciencedirect.com/science/article/abs/pii/S0012369225008128"
      ]
    },
    {
      "rank": 2,
      "name": "Adjuvant Osimertinib (Tagrisso) — Post-Resection",
      "category": "Approved Targeted",
      "intent": null,
      "composite_rating": 9.2,
      "rating_breakdown": {
        "evidence_level": {
          "score": 10,
          "rationale": "ADAURA phase 3 RCT (N=682) published in NEJM demonstrated statistically significant OS and DFS benefit. FDA-approved Category 1 recommendation per NCCN guidelines. Final OS analysis confirmed HR 0.49 for death in stage IB-IIIA."
        },
        "survival_benefit": {
          "score": 9,
          "rationale": "ADAURA showed 5-year OS of 88% vs 78% (HR 0.49, p<0.001) for the overall IB-IIIA population. For stage II-IIIA, 5-year OS was 85% vs 73%. While stage I-specific OS benefit is more modest, DFS improvement is dramatic with HR 0.17 for disease recurrence."
        },
        "accessibility": {
          "score": 9,
          "rationale": "FDA-approved for adjuvant use in resected EGFR-mutant (exon 19 del or L858R) stage IB-IIIA NSCLC. Widely available oral medication. Covered by major insurance plans. 3-year treatment duration."
        },
        "safety_profile": {
          "score": 8,
          "rationale": "Generally well tolerated with manageable side effects. Most common AEs: diarrhea (46%), paronychia (25%), dry skin (23%), stomatitis (17%). Grade 3+ AEs in approximately 20% of patients. Rare but serious ILD risk (~3%)."
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Directly targets EGFR exon 19 deletion — the exact mutation this patient harbors. Exon 19 deletion is associated with superior response to EGFR TKIs compared to L858R. Third-generation TKI with high selectivity for mutant EGFR."
        }
      },
      "mechanism_of_action": "Third-generation, irreversible EGFR tyrosine kinase inhibitor that selectively targets EGFR-sensitizing mutations (exon 19 deletions and L858R) and the T790M resistance mutation, while sparing wild-type EGFR. Blocks downstream RAS-RAF-MEK and PI3K-AKT signaling cascades.",
      "key_evidence": {
        "study_name": "ADAURA",
        "journal": "New England Journal of Medicine",
        "year": 2023,
        "sample_size": 682,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0.49,
          "p_value": 0.001
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [
        "EGFR exon 19 deletion or L858R mutation"
      ],
      "ps_requirement": null,
      "notable_side_effects": [
        "Diarrhea",
        "Paronychia",
        "Dry skin",
        "Stomatitis",
        "Interstitial lung disease (ILD)",
        "QTc prolongation",
        "Decreased appetite"
      ],
      "qol_impact": null,
      "availability": "FDA Approved (adjuvant, stage IB-IIIA EGFR-mutant NSCLC)",
      "source_urls": [
        "https://www.nejm.org/doi/full/10.1056/NEJMoa2304594",
        "https://pubmed.ncbi.nlm.nih.gov/37272535/"
      ]
    },
    {
      "rank": 3,
      "name": "Osimertinib Monotherapy (First-Line for Advanced/Recurrent Disease)",
      "category": "Approved Targeted",
      "intent": null,
      "composite_rating": 8.9,
      "rating_breakdown": {
        "evidence_level": {
          "score": 10,
          "rationale": "FLAURA phase 3 RCT (N=556) published in NEJM established osimertinib as first-line standard for advanced EGFR-mutant NSCLC. FDA Category 1 approval. Median OS 38.6 months vs 31.8 months with first-generation TKIs."
        },
        "survival_benefit": {
          "score": 8,
          "rationale": "FLAURA: median PFS 18.9 months vs 10.2 months (HR 0.46, p<0.001). Median OS 38.6 vs 31.8 months (HR 0.80, p=0.046). Exon 19 deletion patients have even better outcomes. Relevant if disease recurs after initial surgery."
        },
        "accessibility": {
          "score": 9,
          "rationale": "FDA-approved first-line treatment for EGFR-mutant advanced NSCLC. Oral daily tablet. Global availability. Well-established insurance coverage and patient assistance programs."
        },
        "safety_profile": {
          "score": 8,
          "rationale": "Well tolerated with lower rate of grade 3+ AEs (34%) compared to first-generation TKIs (45%). Most common AEs: diarrhea, rash, dry skin, paronychia. ILD incidence ~4%. Superior CNS penetration reduces brain metastasis risk."
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Specifically designed for EGFR exon 19 deletion and L858R mutations. Exon 19 deletion confers even better response than L858R. Covers T790M resistance mutation as well."
        }
      },
      "mechanism_of_action": "Third-generation irreversible EGFR TKI that covalently binds to C797 residue of the EGFR kinase domain. Inhibits both EGFR-sensitizing mutations and T790M resistance mutation with ~200-fold selectivity for mutant vs wild-type EGFR, reducing off-target toxicity.",
      "key_evidence": {
        "study_name": "FLAURA",
        "journal": "New England Journal of Medicine",
        "year": 2020,
        "sample_size": 556,
        "os_months": {
          "treatment": 38.6,
          "control": 31.8,
          "hazard_ratio": 0.8,
          "p_value": 0.046
        },
        "pfs_months": {
          "treatment": 18.9,
          "control": 10.2
        },
        "orr_percent": {
          "treatment": 80,
          "control": 76
        }
      },
      "biomarker_requirements": [
        "EGFR exon 19 deletion or L858R mutation"
      ],
      "ps_requirement": null,
      "notable_side_effects": [
        "Diarrhea",
        "Rash",
        "Dry skin",
        "Paronychia",
        "Stomatitis",
        "Interstitial lung disease",
        "QTc prolongation"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — first-line advanced EGFR-mutant NSCLC",
      "source_urls": [
        "https://www.nejm.org/doi/full/10.1056/NEJMoa1913662",
        "https://www.nejm.org/doi/full/10.1056/NEJMoa2306434"
      ]
    },
    {
      "rank": 4,
      "name": "Segmentectomy (Sublobar Resection) — for Peripheral T1a-b Tumors",
      "category": "Standard of Care",
      "intent": null,
      "composite_rating": 8.6,
      "rating_breakdown": {
        "evidence_level": {
          "score": 9,
          "rationale": "JCOG0802 (N=1106) and CALGB 140503 phase 3 RCTs demonstrate non-inferior or superior OS for segmentectomy vs lobectomy in tumors <=2 cm. Published in Lancet and NEJM. NCCN Category 1 recommendation for selected patients."
        },
        "survival_benefit": {
          "score": 8,
          "rationale": "JCOG0802: 5-year OS 94.3% (segmentectomy) vs 91.1% (lobectomy) for peripheral tumors <=2 cm. CALGB 140503 confirmed DFS non-inferiority. Better preservation of lung function. However, higher local recurrence rate (10.5% vs 5.4%)."
        },
        "accessibility": {
          "score": 9,
          "rationale": "Available at most thoracic surgery centers. Requires expertise in anatomical segmentectomy. Increasingly performed via VATS/robotic approaches. May be preferred if tumor is <=2 cm and peripheral."
        },
        "safety_profile": {
          "score": 8,
          "rationale": "Less parenchyma removed leads to better preserved lung function. Lower perioperative morbidity compared to lobectomy. Particularly advantageous for preserving pulmonary reserve. Similar 30-day mortality to lobectomy."
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Surgical approach is biomarker-agnostic. Applicable regardless of EGFR status. Provides tissue for complete molecular profiling to guide adjuvant therapy decisions."
        }
      },
      "mechanism_of_action": "Anatomical resection of the involved bronchopulmonary segment with adequate margins, preserving uninvolved segments. Includes segmental lymph node sampling. Preserves more lung parenchyma than lobectomy while maintaining oncologic adequacy for small peripheral tumors.",
      "key_evidence": {
        "study_name": "JCOG0802/WJOG4607L and CALGB 140503",
        "journal": "The Lancet / NEJM",
        "year": 2022,
        "sample_size": 1106,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0.0,
          "p_value": 0.0
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [],
      "ps_requirement": null,
      "notable_side_effects": [
        "Air leak",
        "Post-operative pain",
        "Pneumonia",
        "Higher local recurrence risk compared to lobectomy"
      ],
      "qol_impact": null,
      "availability": "Standard of Care — available at thoracic surgery centers",
      "source_urls": [
        "https://pmc.ncbi.nlm.nih.gov/articles/PMC10947770/",
        "https://jtd.amegroups.org/article/view/110237/html"
      ]
    },
    {
      "rank": 5,
      "name": "Osimertinib + Platinum-Pemetrexed Chemotherapy (First-Line for Advanced/Recurrent)",
      "category": "Approved Targeted",
      "intent": null,
      "composite_rating": 8.6,
      "rating_breakdown": {
        "evidence_level": {
          "score": 10,
          "rationale": "FLAURA2 phase 3 RCT (N=557) published in NEJM 2025. Demonstrated significant PFS and OS improvement over osimertinib monotherapy. FDA-approved combination. NCCN Category 1 recommendation."
        },
        "survival_benefit": {
          "score": 9,
          "rationale": "FLAURA2: median OS 47.5 months vs 37.6 months (HR 0.77, p=0.02), a 23% reduction in death risk. Median PFS 25.5 vs 16.7 months (HR 0.62, p<0.001). For exon 19 del, PFS was 27.9 vs 19.4 months. Nearly 10-month OS improvement."
        },
        "accessibility": {
          "score": 8,
          "rationale": "FDA-approved combination. Requires IV chemotherapy infusions in addition to oral osimertinib. Cisplatin/carboplatin and pemetrexed widely available. Insurance coverage established. Relevant if disease recurs post-surgery."
        },
        "safety_profile": {
          "score": 5,
          "rationale": "Addition of chemotherapy increases toxicity significantly. Grade 3+ AEs more frequent than osimertinib alone. Myelosuppression, nausea, fatigue. However, manageable with supportive care. Maintenance pemetrexed adds ongoing toxicity burden."
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Osimertinib component directly targets EGFR exon 19 deletion. Chemotherapy component provides biomarker-independent cytotoxic coverage. Combination addresses both EGFR-driven and non-EGFR resistance pathways."
        }
      },
      "mechanism_of_action": "Combines EGFR-targeted inhibition (osimertinib) with platinum-based DNA crosslinking (cisplatin/carboplatin) and antifolate activity (pemetrexed). The dual approach simultaneously blocks the EGFR signaling pathway and eliminates tumor cells through DNA damage, delaying emergence of resistance.",
      "key_evidence": {
        "study_name": "FLAURA2",
        "journal": "New England Journal of Medicine",
        "year": 2025,
        "sample_size": 557,
        "os_months": {
          "treatment": 47.5,
          "control": 37.6,
          "hazard_ratio": 0.77,
          "p_value": 0.02
        },
        "pfs_months": {
          "treatment": 25.5,
          "control": 16.7
        },
        "orr_percent": {
          "treatment": 83,
          "control": 76
        }
      },
      "biomarker_requirements": [
        "EGFR exon 19 deletion or L858R mutation"
      ],
      "ps_requirement": null,
      "notable_side_effects": [
        "Myelosuppression (neutropenia, anemia, thrombocytopenia)",
        "Nausea and vomiting",
        "Fatigue",
        "Diarrhea",
        "Peripheral neuropathy",
        "Interstitial lung disease",
        "Nephrotoxicity (with cisplatin)"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — first-line combination for advanced EGFR-mutant NSCLC",
      "source_urls": [
        "https://www.nejm.org/doi/full/10.1056/NEJMoa2510308",
        "https://www.nejm.org/doi/full/10.1056/NEJMoa2306434"
      ]
    },
    {
      "rank": 6,
      "name": "Adjuvant Cisplatin-Based Chemotherapy Followed by Osimertinib",
      "category": "Standard of Care",
      "intent": null,
      "composite_rating": 8.2,
      "rating_breakdown": {
        "evidence_level": {
          "score": 9,
          "rationale": "Sequential adjuvant chemotherapy followed by osimertinib is supported by ADAURA subgroup analyses and NCCN Category 1 recommendation. The LACE meta-analysis supports adjuvant chemotherapy for resected NSCLC (HR 0.89 for death), though benefit is modest for stage IB specifically."
        },
        "survival_benefit": {
          "score": 8,
          "rationale": "Combined approach: LACE meta-analysis showed 5.4% absolute OS benefit at 5 years with adjuvant chemotherapy. ADAURA showed additional survival benefit with osimertinib. Sequential strategy ensures both cytotoxic and targeted coverage, though stage IB-specific chemo benefit is debated."
        },
        "accessibility": {
          "score": 9,
          "rationale": "Both cisplatin-based doublets and osimertinib are FDA-approved and widely available. Standard regimens include cisplatin/pemetrexed (preferred for adenocarcinoma) or cisplatin/vinorelbine. Insurance coverage well-established."
        },
        "safety_profile": {
          "score": 6,
          "rationale": "Cisplatin-based chemotherapy carries significant side effects: nausea/vomiting, nephrotoxicity, ototoxicity, myelosuppression. Approximately 50% of patients complete planned 4 cycles. Followed by 3 years of osimertinib with its own toxicity profile. Cumulative burden is substantial."
        },
        "biomarker_match": {
          "score": 9,
          "rationale": "Cisplatin chemotherapy is biomarker-agnostic. Osimertinib component directly targets the patient's EGFR exon 19 deletion. The combination addresses both biomarker-driven and non-biomarker-driven recurrence mechanisms."
        }
      },
      "mechanism_of_action": "Cisplatin creates DNA crosslinks causing apoptosis in rapidly dividing cells. Pemetrexed inhibits thymidylate synthase, DHFR, and GARFT enzymes critical for DNA synthesis. Osimertinib then provides sustained EGFR pathway suppression to eliminate residual EGFR-driven micrometastatic disease.",
      "key_evidence": {
        "study_name": "LACE Meta-Analysis / ADAURA Sequential Strategy",
        "journal": "Journal of Clinical Oncology / NEJM",
        "year": 2023,
        "sample_size": 4584,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0.89,
          "p_value": 0.005
        },
        "pfs_months": {
          "treatment": 0,
          "control": 0
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [
        "EGFR exon 19 deletion or L858R (for osimertinib component)"
      ],
      "ps_requirement": null,
      "notable_side_effects": [
        "Nausea and vomiting",
        "Nephrotoxicity",
        "Myelosuppression",
        "Peripheral neuropathy",
        "Ototoxicity",
        "Fatigue",
        "Diarrhea (osimertinib)",
        "Paronychia (osimertinib)"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — both components standard of care",
      "source_urls": [
        "https://www.nejm.org/doi/full/10.1056/NEJMoa2304594",
        "https://ascopubs.org/doi/10.1200/JCO.19.02674"
      ]
    },
    {
      "rank": 7,
      "name": "Amivantamab + Lazertinib (Rybrevant + Lazcluze)",
      "category": "Approved Targeted",
      "intent": null,
      "composite_rating": 8.1,
      "rating_breakdown": {
        "evidence_level": {
          "score": 10,
          "rationale": "MARIPOSA phase 3 RCT (N=1074) published in NEJM. Demonstrated significant PFS and OS benefit vs osimertinib. FDA-approved January 2025. NCCN Category 1 recommendation for first-line advanced EGFR-mutant NSCLC."
        },
        "survival_benefit": {
          "score": 8,
          "rationale": "MARIPOSA: median PFS 23.7 vs 16.6 months (HR 0.70, p<0.001). 3-year OS 60% vs 51% (HR 0.75, p=0.005). Significant benefit but head-to-head OS advantage over osimertinib+chemo not yet established. Relevant for recurrent disease."
        },
        "accessibility": {
          "score": 7,
          "rationale": "FDA-approved since January 2025. Subcutaneous formulation approved December 2025 for improved convenience. Requires biweekly IV or monthly SC administration plus daily oral lazertinib. Higher cost and access barriers than osimertinib alone."
        },
        "safety_profile": {
          "score": 4,
          "rationale": "Grade 3+ AEs in 80% of patients (vs 52% with osimertinib). Significant skin toxicity, infusion reactions (66%), venous thromboembolism (increased risk), peripheral edema, paronychia. Higher treatment discontinuation rate. Requires careful patient selection."
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Amivantamab is a bispecific antibody targeting both EGFR and MET receptors, addressing a common resistance pathway. Lazertinib is a third-gen EGFR TKI. Dual EGFR+MET targeting is highly relevant for EGFR exon 19 deletion."
        }
      },
      "mechanism_of_action": "Amivantamab is a bispecific antibody that simultaneously binds EGFR and MET receptors, blocking ligand binding, promoting receptor degradation, and engaging immune effector cells via its Fc domain. Lazertinib is a third-generation brain-penetrant EGFR TKI. The combination provides extracellular and intracellular EGFR blockade plus MET pathway inhibition.",
      "key_evidence": {
        "study_name": "MARIPOSA",
        "journal": "New England Journal of Medicine",
        "year": 2025,
        "sample_size": 1074,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0.75,
          "p_value": 0.005
        },
        "pfs_months": {
          "treatment": 23.7,
          "control": 16.6
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [
        "EGFR exon 19 deletion or L858R mutation"
      ],
      "ps_requirement": null,
      "notable_side_effects": [
        "Infusion-related reactions",
        "Skin rash/acneiform dermatitis",
        "Paronychia",
        "Venous thromboembolism",
        "Peripheral edema",
        "Hypoalbuminemia",
        "Diarrhea",
        "Stomatitis"
      ],
      "qol_impact": null,
      "availability": "FDA Approved (January 2025) — first-line advanced EGFR-mutant NSCLC",
      "source_urls": [
        "https://www.nejm.org/doi/full/10.1056/NEJMoa2503001",
        "https://www.nejm.org/doi/full/10.1056/NEJMoa2403614"
      ]
    },
    {
      "rank": 8,
      "name": "Osimertinib Consolidation (Post-Chemoradiation for Unresectable Stage III)",
      "category": "Approved Targeted",
      "intent": null,
      "composite_rating": 8.1,
      "rating_breakdown": {
        "evidence_level": {
          "score": 9,
          "rationale": "LAURA phase 3 RCT demonstrated dramatic PFS benefit for consolidation osimertinib after chemoradiation in unresectable stage III EGFR-mutant NSCLC. ASCO guideline recommendation. FDA-approved indication."
        },
        "survival_benefit": {
          "score": 7,
          "rationale": "LAURA: median PFS 39.1 vs 5.6 months (HR 0.16, p<0.001) — a profound improvement. OS data immature at initial analysis. Relevant only if patient's stage I disease is reclassified or becomes locally advanced. Dramatic PFS improvement."
        },
        "accessibility": {
          "score": 8,
          "rationale": "FDA-approved for unresectable stage III EGFR-mutant NSCLC after chemoradiation. Osimertinib is widely available. ASCO guideline recommendation issued 2025. Not applicable for this patient's current stage I disease."
        },
        "safety_profile": {
          "score": 7,
          "rationale": "Well tolerated after chemoradiation completion. Most AEs are low grade (diarrhea, dermatitis). Radiation pneumonitis must be monitored. 3% ILD/pneumonitis risk. Sequential radiation then TKI generally manageable."
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Directly targets EGFR exon 19 deletion. Specifically approved for EGFR exon 19 del or L858R mutations. Excellent biomarker match for this patient's molecular profile."
        }
      },
      "mechanism_of_action": "Following concurrent chemoradiation for unresectable stage III disease, osimertinib is administered as maintenance/consolidation therapy to suppress residual EGFR-driven microscopic disease. The combination of radiation-induced tumor damage and sustained EGFR pathway inhibition aims to prevent local and distant recurrence.",
      "key_evidence": {
        "study_name": "LAURA",
        "journal": "New England Journal of Medicine",
        "year": 2024,
        "sample_size": 216,
        "os_months": {
          "treatment": 0,
          "control": 0,
          "hazard_ratio": 0.0,
          "p_value": 0.0
        },
        "pfs_months": {
          "treatment": 39.1,
          "control": 5.6
        },
        "orr_percent": {
          "treatment": 0,
          "control": 0
        }
      },
      "biomarker_requirements": [
        "EGFR exon 19 deletion or L858R mutation",
        "Unresectable stage III NSCLC",
        "Completed concurrent chemoradiation without progression"
      ],
      "ps_requirement": null,
      "notable_side_effects": [
        "Diarrhea",
        "Radiation dermatitis",
        "Radiation pneumonitis",
        "Interstitial lung disease",
        "Paronychia",
        "Dry skin"
      ],
      "qol_impact": null,
      "availability": "FDA Approved — consolidation after CRT in stage III EGFR-mutant NSCLC",
      "source_urls": [
        "https://www.cancertherapyadvisor.com/news/osimertinib-consolidation-egfr-mutant-stage-iii-nsclc/"
      ]
    },
    {
      "rank": 9,
      "name": "Stereotactic Body Radiation Therapy (SBRT)",
      "category": "Standard of Care",
      "intent": null,
      "composite_rating": 7.7,
      "rating_breakdown": {
        "evidence_level": {
          "score": 8,
          "rationale": "Multiple prospective studies and pooled analyses support SBRT for medically inoperable stage I NSCLC. 3-year local control rates of 90-98%. NCCN Category 2A for medically inoperable patients. Not standard for surgical candidates."
        },
        "survival_benefit": {
          "score": 6,
          "rationale": "3-year OS of 82-95% in selected populations, but distant failure up to 33% at 3 years. Inferior to surgery for operable patients. 2-year OS of 97% in medically operable patients who refused surgery. Not the primary approach for this surgical candidate."
        },
        "accessibility": {
          "score": 8,
          "rationale": "Widely available at radiation oncology centers. Non-invasive outpatient treatment completed in 3-5 sessions. Particularly relevant as a backup option if patient becomes medically inoperable. No general anesthesia required."
        },
        "safety_profile": {
          "score": 9,
          "rationale": "Very well tolerated with minimal acute toxicity. Low treatment-related morbidity (10-21%). No surgical risks. Fatigue and mild chest wall pain are the most common side effects. Rare pneumonitis risk."
        },
        "biomarker_match": {
          "score": 10,
          "rationale": "Radiation is biomarker-agnostic, effective regardless of molecular profile. Can be combined with systemic targeted therapy. Applicable across all NSCLC subtypes."
